im1 = axs[0,1].imshow(S_map, extent=ext, origin='lower', cmap='RdBu_r', vmin=-0.5, vmax=0.5)
axs[0,1].set_title('Dual-port Faraday: normalised difference S')
plt.colorbar(im1, ax=axs[0,1], fraction=0.03, label='S = (Iv-Iu)/(Iv+Iu)')
